@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --bg: #0a0c10;
  --card: #151820;
  --accent: #7c3aed;
  --cyan: #06b6d4;
  --green: #1B4332;
  --text-primary: #ffffff;
  --text-secondary: #a0a0a0;
  --border: #2a2a3e;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  background: var(--bg);
  color: var(--text-primary);
  font-family: var(--font-inter), -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto', sans-serif;
  overflow-x: hidden;
}

/* Scrollbar hiding utilities */
.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

.scrollbar-hide::-webkit-scrollbar {
  display: none;
}

/* Safe area padding for iOS */
.safe-area-top {
  padding-top: max(env(safe-area-inset-top), 1rem);
}

.safe-area-bottom {
  padding-bottom: max(env(safe-area-inset-bottom), 1rem);
}

.safe-area-full {
  padding-top: max(env(safe-area-inset-top), 1rem);
  padding-bottom: max(env(safe-area-inset-bottom), 1rem);
  padding-left: max(env(safe-area-inset-left), 1rem);
  padding-right: max(env(safe-area-inset-right), 1rem);
}

/* Animation keyframes */
@keyframes fadeIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes slideUp {
  from {
    transform: translateY(20px);
    opacity: 0;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}

@keyframes slideIn {
  from {
    transform: translateX(-20px);
    opacity: 0;
  }
  to {
    transform: translateX(0);
    opacity: 1;
  }
}

@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

@keyframes shimmer {
  0% {
    background-position: -1000px 0;
  }
  100% {
    background-position: 1000px 0;
  }
}

/* Utility classes for animations */
.animate-fade-in {
  animation: fadeIn 0.3s ease-in;
}

.animate-slide-up {
  animation: slideUp 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

.animate-slide-in {
  animation: slideIn 0.3s ease-out;
}

.animate-pulse {
  animation: pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite;
}

/* Skeleton loader */
.skeleton {
  background: linear-gradient(
    90deg,
    var(--card) 25%,
    var(--border) 50%,
    var(--card) 75%
  );
  background-size: 1000px 100%;
  animation: shimmer 2s infinite;
}

/* Toast animations */
@keyframes toastSlideIn {
  from {
    transform: translateY(100%);
    opacity: 0;
  }
  to {
    transform: translateY(0);
    opacity: 1;
  }
}

@keyframes toastSlideOut {
  from {
    transform: translateY(0);
    opacity: 1;
  }
  to {
    transform: translateY(100%);
    opacity: 0;
  }
}

.toast-enter {
  animation: toastSlideIn 0.3s ease-out;
}

.toast-exit {
  animation: toastSlideOut 0.3s ease-in;
}

/* Focus visible styles for accessibility */
:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

button:focus-visible,
a:focus-visible,
input:focus-visible,
textarea:focus-visible,
select:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

/* Smooth transitions */
@layer components {
  .transition-smooth {
    @apply transition-all duration-200 ease-in-out;
  }

  .card {
    @apply bg-card rounded-lg border border-border p-4;
  }

  .btn-base {
    @apply px-4 py-2 rounded-lg font-medium transition-smooth focus-visible:outline-2 focus-visible:outline-offset-2;
  }

  .btn-primary {
    @apply btn-base bg-accent text-white hover:bg-purple-600 active:bg-purple-800;
  }

  .btn-secondary {
    @apply btn-base bg-card text-white hover:bg-border active:bg-gray-700;
  }
}

/* Responsive typography */
@media (max-width: 640px) {
  body {
    font-size: 16px;
  }
}

