'use client';

import { useStore } from '@/lib/store';
import { useEffect } from 'react';

// Import all page components
import AuthPage from '@/components/layout/AuthPage';
import OnboardingScreen from '@/components/onboarding/OnboardingScreen';
import HomePage from '@/components/pages/HomePage';
import MapPage from '@/components/pages/MapPage';
import ExplorePage from '@/components/pages/ExplorePage';
import MessagesPage from '@/components/pages/MessagesPage';
import ProfilePage from '@/components/pages/ProfilePage';
import CoachAIPage from '@/components/pages/CoachAIPage';
import CoachHubPage from '@/components/pages/CoachHubPage';
import MarketplacePage from '@/components/pages/MarketplacePage';
import TrailDetailPage from '@/components/pages/TrailDetailPage';
import UserProfilePage from '@/components/pages/UserProfilePage';
import TeamsPage from '@/components/pages/TeamsPage';
import PrivacyPage from '@/components/pages/PrivacyPage';
import CGUPage from '@/components/pages/CGUPage';

// Import layout components
import TopBar from './TopBar';
import BottomNav from './BottomNav';
import CookieBanner from './CookieBanner';
import Toast from '@/components/ui/Toast';

export default function AppShell() {
  const {
    isLoggedIn,
    hasCompletedOnboarding,
    currentPage,
    subPage,
    fontSize,
    showCookieBanner,
    gdprConsent,
  } = useStore();

  // Set document language to French
  useEffect(() => {
    document.documentElement.lang = 'fr';
  }, []);

  // Render logic based on auth and onboarding state
  const renderContent = () => {
    // Not logged in - show auth
    if (!isLoggedIn) {
      return <AuthPage />;
    }

    // Logged in but not onboarded - show onboarding
    if (!hasCompletedOnboarding) {
      return <OnboardingScreen />;
    }

    // Logged in and onboarded - check for subpage
    if (subPage) {
      if (typeof subPage === 'string') {
        // Simple string subpages
        switch (subPage) {
          case 'coach-ai':
            return <CoachAIPage />;
          case 'coach-hub':
            return <CoachHubPage />;
          case 'marketplace':
            return <MarketplacePage />;
          case 'teams':
            return <TeamsPage />;
          case 'privacy':
            return <PrivacyPage />;
          case 'cgu':
            return <CGUPage />;
          default:
            return <HomePage />;
        }
      } else {
        // Object-based subpages with parameters
        switch (subPage.type) {
          case 'trail-detail':
            return <TrailDetailPage trailId={subPage.trailId} />;
          case 'user-profile':
            return <UserProfilePage userId={subPage.userId} />;
          case 'team-detail':
            return <TeamsPage teamId={subPage.teamId} />;
          case 'conversation':
            return <MessagesPage conversationId={subPage.conversationId} />;
          default:
            return <HomePage />;
        }
      }
    }

    // Render main navigation pages
    switch (currentPage) {
      case 'home':
        return <HomePage />;
      case 'map':
        return <MapPage />;
      case 'explore':
        return <ExplorePage />;
      case 'messages':
        return <MessagesPage />;
      case 'profile':
        return <ProfilePage />;
      default:
        return <HomePage />;
    }
  };

  const baseFontSize = fontSize === 'large' ? '18px' : '16px';

  return (
    <div
      className="min-h-screen bg-[var(--bg)] text-white flex flex-col max-w-[430px] mx-auto relative"
      style={{ fontSize: baseFontSize }}
      role="application"
      aria-label="Adventurer - Application d'aventure outdoor"
    >
      {/* Cookie Banner - only show if logged in, onboarded, and consent not given */}
      {showCookieBanner && gdprConsent === null && isLoggedIn && hasCompletedOnboarding && (
        <CookieBanner />
      )}

      {/* Top Bar - only show if logged in, onboarded, and no subpage */}
      {isLoggedIn && hasCompletedOnboarding && !subPage && <TopBar />}

      {/* Main Content Area */}
      <main
        className="flex-1 overflow-y-auto pb-20"
        id="main-content"
        role="main"
        aria-label="Contenu principal"
      >
        {renderContent()}
      </main>

      {/* Bottom Navigation - only show if logged in, onboarded, and no subpage */}
      {isLoggedIn && hasCompletedOnboarding && !subPage && <BottomNav />}

      {/* Toast Notifications */}
      <Toast />
    </div>
  );
}

'use client';
import { useState } from 'react';
import { useStore } from '@/lib/store';

export default function AuthPage() {
  const { login, setSubPage } = useStore();
  const [mode, setMode] = useState<'login' | 'signup'>('login');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [acceptGDPR, setAcceptGDPR] = useState(false);
  const [error, setError] = useState('');

  const handleGoogleLogin = () => {
    login('google', 'Guillaume', 'guillaumecoulon1@gmail.com');
  };

  const handleEmailSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    if (!email || !password) {
      setError('Veuillez remplir tous les champs.');
      return;
    }
    if (mode === 'signup' && !name) {
      setError('Veuillez entrer votre nom.');
      return;
    }
    if (mode === 'signup' && !acceptGDPR) {
      setError('Vous devez accepter les conditions d\'utilisation et la politique de confidentialité.');
      return;
    }
    login('email', mode === 'signup' ? name : email.split('@')[0], email);
  };

  return (
    <div className="min-h-screen bg-[var(--bg)] flex flex-col max-w-[430px] mx-auto">
      {/* Hero with mountain */}
      <div className="relative h-64 bg-gradient-to-b from-green-900/40 via-[var(--bg)] to-[var(--bg)] flex items-center justify-center overflow-hidden">
        <svg viewBox="0 0 430 200" className="absolute bottom-0 w-full" aria-hidden="true">
          <defs>
            <linearGradient id="mtn1" x1="0%" y1="0%" x2="0%" y2="100%">
              <stop offset="0%" stopColor="#1B4332" />
              <stop offset="100%" stopColor="#0a0c10" />
            </linearGradient>
            <linearGradient id="mtn2" x1="0%" y1="0%" x2="0%" y2="100%">
              <stop offset="0%" stopColor="#2D6A4F" />
              <stop offset="100%" stopColor="#0a0c10" />
            </linearGradient>
          </defs>
          <polygon points="0,200 80,60 160,200" fill="url(#mtn1)" opacity="0.5" />
          <polygon points="100,200 215,30 330,200" fill="url(#mtn2)" opacity="0.7" />
          <polygon points="250,200 350,70 430,200" fill="url(#mtn1)" opacity="0.4" />
          <circle cx="350" cy="50" r="30" fill="#F77F00" opacity="0.8" />
        </svg>
        <div className="relative z-10 text-center">
          <h1 className="text-3xl font-bold bg-gradient-to-r from-green-400 to-emerald-300 bg-clip-text text-transparent">Adventurer</h1>
          <p className="text-gray-400 mt-1" style={{ fontSize: '14px' }}>L'aventure commence ici</p>
        </div>
      </div>

      {/* Auth Form */}
      <div className="flex-1 px-6 py-4 space-y-5">
        {/* Mode Toggle */}
        <div className="flex bg-white/5 rounded-xl p-1" role="tablist" aria-label="Mode de connexion">
          <button
            type="button"
            role="tab"
            aria-selected={mode === 'login'}
            className={`flex-1 py-2.5 rounded-lg font-medium text-sm transition focus-visible:outline focus-visible:outline-2 focus-visible:outline-[var(--accent)] ${
              mode === 'login' ? 'bg-[var(--accent)] text-white' : 'text-gray-400 hover:text-white'
            }`}
            onClick={() => {
              setMode('login');
              setError('');
            }}
            aria-label="Mode connexion"
          >
            Connexion
          </button>
          <button
            type="button"
            role="tab"
            aria-selected={mode === 'signup'}
            className={`flex-1 py-2.5 rounded-lg font-medium text-sm transition focus-visible:outline focus-visible:outline-2 focus-visible:outline-[var(--accent)] ${
              mode === 'signup' ? 'bg-[var(--accent)] text-white' : 'text-gray-400 hover:text-white'
            }`}
            onClick={() => {
              setMode('signup');
              setError('');
            }}
            aria-label="Mode inscription"
          >
            Inscription
          </button>
        </div>

        {/* Google Button */}
        <button
          type="button"
          className="w-full py-3 bg-white text-gray-900 rounded-xl font-semibold flex items-center justify-center gap-3 hover:bg-gray-100 transition focus-visible:outline focus-visible:outline-2 focus-visible:outline-[var(--accent)]"
          onClick={handleGoogleLogin}
          aria-label="Continuer avec Google"
        >
          <svg className="w-5 h-5" viewBox="0 0 24 24" aria-hidden="true">
            <path
              d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 01-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z"
              fill="#4285F4"
            />
            <path
              d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
              fill="#34A853"
            />
            <path
              d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
              fill="#FBBC05"
            />
            <path
              d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
              fill="#EA4335"
            />
          </svg>
          Continuer avec Google
        </button>

        <div className="flex items-center gap-3">
          <div className="flex-1 h-px bg-white/10"></div>
          <span className="text-gray-500 text-sm" style={{ fontSize: '14px' }}>
            ou
