          </div>

          {mode === 'signup' && (
            <div className="flex items-start gap-2 py-2">
              <input
                id="gdpr-consent"
                type="checkbox"
                checked={acceptGDPR}
                onChange={e => setAcceptGDPR(e.target.checked)}
