                  politique de confidentialité
                </button>
                . Mes données sont traitées conformément au RGPD.
              </label>
            </div>
          )}

          {error && (
            <div
              className="p-3 bg-red-900/30 border border-red-800/50 rounded-xl text-red-300 text-sm"
              role="alert"
              style={{ fontSize: '14px' }}
