              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full py-3 bg-[var(--accent)] text-white rounded-xl font-bold hover:opacity-90 transition focus-visible:outline focus-visible:outline-2 focus-visible:outline-white"
