        </form>

        {mode === 'login' && (
          <button
            type="button"
            className="w-full text-center text-sm text-gray-400 hover:text-[var(--accent)] transition focus-visible:outline focus-visible:outline-2 focus-visible:outline-[var(--accent)] rounded"
