        )}

        {/* Footer links */}
        <div
          className="pt-4 border-t border-white/5 flex justify-center gap-4 text-sm text-gray-500"
          style={{ fontSize: '14px' }}
        >
          <button
            type="button"
            className="hover:text-gray-300 transition focus-visible:outline focus-visible:outline-2 focus-visible:outline-[var(--accent)] rounded px-1"
            aria-label="Politique de confidentialité"
          >
            Confidentialité
          </button>
          <span aria-hidden="true">·</span>
          <button
            type="button"
            className="hover:text-gray-300 transition focus-visible:outline focus-visible:outline-2 focus-visible:outline-[var(--accent)] rounded px-1"
            aria-label="Conditions générales d'utilisation"
          >
            CGU
          </button>
          <span aria-hidden="true">·</span>
          <button
            type="button"
            className="hover:text-gray-300 transition focus-visible:outline focus-visible:outline-2 focus-visible:outline-[var(--accent)] rounded px-1"
            aria-label="À propos d'Adventurer"
          >
            À propos
          </button>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useStore, Page } from '@/lib/store';

interface Tab {
  id: Page;
  label: string;
  icon: string;
  activeIcon: string;
  ariaLabel: string;
}

const tabs: Tab[] = [
  {
    id: 'home',
    label: 'Accueil',
    icon: '🏠',
    activeIcon: '🏡',
    ariaLabel: 'Aller à l\'accueil',
  },
  {
    id: 'map',
    label: 'Carte',
    icon: '🗺️',
    activeIcon: '🗺️',
    ariaLabel: 'Voir la carte des sentiers',
  },
  {
    id: 'explore',
    label: 'Explorer',
    icon: '🔍',
    activeIcon: '🔎',
    ariaLabel: 'Explorer les destinations',
  },
  {
    id: 'messages',
    label: 'Messages',
    icon: '💬',
    activeIcon: '💬',
    ariaLabel: 'Voir les messages',
  },
  {
    id: 'profile',
    label: 'Profil',
    icon: '👤',
    activeIcon: '👤',
    ariaLabel: 'Voir mon profil',
  },
];

export default function BottomNav() {
  const { currentPage, setPage } = useStore();

  const handleTabClick = (tabId: Page) => {
    setPage(tabId);
  };

  const handleTabKeyDown = (
    e: React.KeyboardEvent<HTMLButtonElement>,
    tabId: Page
  ) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      handleTabClick(tabId);
    }

    // Arrow key navigation
    const currentIndex = tabs.findIndex((tab) => tab.id === currentPage);
    let newIndex = currentIndex;

    if (e.key === 'ArrowRight' || e.key === 'ArrowDown') {
      e.preventDefault();
      newIndex = (currentIndex + 1) % tabs.length;
    } else if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') {
      e.preventDefault();
      newIndex = (currentIndex - 1 + tabs.length) % tabs.length;
    }

    if (newIndex !== currentIndex) {
      handleTabClick(tabs[newIndex].id);
      // Focus the newly active tab
      setTimeout(() => {
        const button = document.querySelector(
          `[role="tab"][aria-selected="true"]`
        ) as HTMLButtonElement;
        button?.focus();
      }, 0);
    }
  };

  return (
    <nav
      className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-[430px] bg-[var(--bg)]/95 backdrop-blur-sm border-t border-white/10 flex justify-around py-2 pb-[max(0.5rem,env(safe-area-inset-bottom))] z-40"
      role="navigation"
      aria-label="Navigation principale - Onglets de l'application"
    >
      {tabs.map((tab) => {
        const isActive = currentPage === tab.id;

        return (
          <button
            key={tab.id}
            type="button"
            role="tab"
            aria-selected={isActive}
            aria-label={tab.ariaLabel}
            aria-current={isActive ? 'page' : undefined}
            className={`flex flex-col items-center gap-0.5 px-3 py-1 rounded-lg transition-all duration-200 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 ${
              isActive
                ? 'text-[var(--accent)]'
                : 'text-gray-500 hover:text-gray-300 active:text-gray-200'
            } focus-visible:outline-[var(--accent)]`}
            onClick={() => handleTabClick(tab.id)}
            onKeyDown={(e) => handleTabKeyDown(e, tab.id)}
            tabIndex={isActive ? 0 : -1}
          >
            {/* Icon */}
            <span
              className="text-xl transition-transform duration-200"
              role="img"
              aria-hidden="true"
            >
              {isActive ? tab.activeIcon : tab.icon}
            </span>

            {/* Label */}
            <span
              className={`text-xs font-medium transition-colors duration-200 ${
                isActive ? 'text-[var(--accent)]' : 'text-gray-500'
              }`}
              style={{ fontSize: '14px' }}
            >
              {tab.label}
            </span>

            {/* Active indicator dot */}
            {isActive && (
              <div
                className="w-1.5 h-1.5 bg-[var(--accent)] rounded-full mt-0.5"
                aria-hidden="true"
              />
            )}
          </button>
        );
      })}
    </nav>
  );
}

