  const suggestions = getSuggestions(selectedSports);

  const generate = (prompt: string) => {
    if (!prompt.trim()) return;
    setLoading(true);
    setPlan(null);
    setTimeout(() => {
      setPlan(generateAIResponse(prompt, selectedSports));
