                style={{fontSize:'14px'}}
              >
                Adopter ce plan
              </button>
              <button
                type="button"
                className="flex-1 py-3 bg-white/5 text-white rounded-xl font-medium hover:bg-white/10 transition focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-white/20"
