                  setPlan(null);
                  setInput('');
                }}
                aria-label="Créer un nouvel objectif"
                style={{fontSize:'14px'}}
              >
                Nouvel objectif
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

