import { getSportEmoji, SPORTS } from '@/lib/sports-config';

type CategoryFilter = 'routes' | 'spots' | 'defis' | 'equipes' | 'materiel' | 'classement';

export default function ExplorePage() {
  const { selectedSports, showToast, setPage, setSubPage } = useStore();
