  const [searchQuery, setSearchQuery] = useState('');

  const categories = [
    { id: 'routes' as const, label: 'Routes', icon: '🗺️' },
    { id: 'spots' as const, label: 'Spots', icon: '📍' },
    { id: 'defis' as const, label: 'Défis', icon: '🏁' },
    { id: 'equipes' as const, label: 'Équipes', icon: '👥' },
    { id: 'materiel' as const, label: 'Matériel', icon: '🛠️' },
    { id: 'classement' as const, label: 'Classement', icon: '🏆' },
  ];

  // Filter routes by search and sports
  const filteredRoutes = GPX_ROUTES.filter((route) => {
    const matchesSearch = route.name.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesSport = selectedSports.length === 0 || selectedSports.includes(route.sport);
    return matchesSearch && matchesSport;
  });

  // Filter spots by search and sports
  const filteredSpots = MAP_SPOTS.filter((spot) => {
    const matchesSearch = spot.name.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesSport = selectedSports.length === 0 || spot.sports.some(s => selectedSports.includes(s));
    return matchesSearch && matchesSport;
  });

  // Filter défis
  const filteredDefis = getUpcomingEvents().filter((event) => {
    return event.title.toLowerCase().includes(searchQuery.toLowerCase());
  });

  // Filter teams
  const filteredTeams = TEAMS.filter((team) => {
    const matchesSearch = team.name.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesSport = selectedSports.length === 0 || selectedSports.includes(team.sport);
    return matchesSearch && matchesSport;
  });

  // Filter market items
  const filteredMarket = MARKET_SELL.filter((item) => {
    return item.title.toLowerCase().includes(searchQuery.toLowerCase());
  });

  // Filter leaderboard
  const leaderboard = USER_PROFILES.sort((a, b) => (b.stats?.totalAttempts || 0) - (a.stats?.totalAttempts || 0)).slice(0, 10);

  const getDifficultyColor = (difficulty: string) => {
    switch (difficulty) {
      case 'Facile': return 'bg-green-100 text-green-800';
      case 'Moyen': return 'bg-yellow-100 text-yellow-800';
      case 'Difficile': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
