                      <span className="text-sm bg-gray-100 px-2 py-1 rounded">{route.duration}</span>
                      <span className={`text-sm px-2 py-1 rounded font-semibold ${getDifficultyColor(route.difficulty)}`}>
                        {route.difficulty}
                      </span>
                    </div>
                    <button
                      onClick={() => setPage('map')}
                      aria-label={`View ${route.name} on map`}
                      className="text-blue-600 font-semibold text-sm hover:underline"
