        {/* DEFIS TAB */}
        {activeCategory === 'defis' && (
          <div className="space-y-3">
            {filteredDefis.map((event) => (
              <div key={event.id} className="border rounded-lg p-4 bg-white hover:shadow-md transition-shadow">
                <p className="text-gray-600 text-sm mb-1">{event.date}</p>
