          aria-expanded={fabMenuOpen}
          aria-haspopup="menu"
        >
          {fabMenuOpen ? '✕' : '+'}
        </button>
      </div>
    </main>
  );
}

'use client';
import { useState, useEffect, useRef } from 'react';
import { useStore } from '@/lib/store';
import { MAP_SPOTS, GPX_ROUTES, NEARBY_PEOPLE } from '@/lib/mock-data';
import { getSportEmoji } from '@/lib/sports-config';

export default function MapPage() {
  const { selectedSports, setSubPage, showToast } = useStore();
  const [search, setSearch] = useState('');
  const [sportFilter, setSportFilter] = useState<string | null>(null);
  const [selectedSpot, setSelectedSpot] = useState<typeof MAP_SPOTS[0] | null>(null);
  const [mapReady, setMapReady] = useState(false);
  const mapRef = useRef<any>(null);
  const mapContainerRef = useRef<HTMLDivElement>(null);

  const filteredSpots = MAP_SPOTS.filter(s => {
    if (search && !s.name.toLowerCase().includes(search.toLowerCase()) && !s.type.toLowerCase().includes(search.toLowerCase())) return false;
    if (sportFilter && s.sport !== sportFilter) return false;
    return true;
  });

  const sports = [...new Set(MAP_SPOTS.map(s => s.sport))];

  // Load Leaflet map
  useEffect(() => {
    if (typeof window === 'undefined' || mapRef.current) return;
    const loadMap = async () => {
      const L = (await import('leaflet')).default;
      // Fix marker icon
      delete (L.Icon.Default.prototype as any)._getIconUrl;
      L.Icon.Default.mergeOptions({
        iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
        iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
        shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
      });

      if (!mapContainerRef.current) return;
      const map = L.map(mapContainerRef.current).setView([45.87, 6.86], 10);
      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '© OpenStreetMap contributors'
      }).addTo(map);
      mapRef.current = { map, L, markers: [] as any[] };
      setMapReady(true);
    };
    loadMap();
    return () => {
      if (mapRef.current) {
        mapRef.current.map.remove();
        mapRef.current = null;
      }
    };
  }, []);

  // Update markers when filters change
  useEffect(() => {
    if (!mapRef.current || !mapReady) return;
    const { map, L, markers } = mapRef.current;
    markers.forEach((m: any) => map.removeLayer(m));
    mapRef.current.markers = [];

    // Add spot markers
    filteredSpots.forEach(spot => {
      const icon = L.divIcon({
        className: 'custom-marker',
        html: `<div style="font-size:24px;text-align:center;cursor:pointer">${spot.emoji}</div>`,
        iconSize: [30, 30],
        iconAnchor: [15, 15]
      });
      const marker = L.marker([spot.lat, spot.lng], { icon }).addTo(map);
      marker.on('click', () => setSelectedSpot(spot));
      mapRef.current.markers.push(marker);
    });

    // Add GPX routes
    GPX_ROUTES.forEach(route => {
      const polyline = L.polyline(
        route.coordinates.map(c => [c[0], c[1]]),
        { color: route.color, weight: 3, opacity: 0.7 }
      ).addTo(map);
      mapRef.current.markers.push(polyline);
    });
  }, [mapReady, search, sportFilter, filteredSpots]);

  const handleSearch = () => {
    if (!search || !mapRef.current || filteredSpots.length === 0) {
      showToast('Aucun spot trouvé', 'warning', '🔍');
      return;
    }
    const first = filteredSpots[0];
    mapRef.current.map.setView([first.lat, first.lng], 13);
    setSelectedSpot(first);
    showToast(`Centré sur ${first.name}`, 'success', '📍');
  };

  return (
    <div className="h-screen bg-[var(--bg)] max-w-[430px] mx-auto flex flex-col relative">
      <link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" />

      {/* Search + Filters overlay */}
      <div className="absolute top-2 left-2 right-2 z-[1000] space-y-2">
        <div className="flex gap-2">
          <input
            type="search"
            value={search}
            onChange={e => setSearch(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSearch()}
            placeholder="🔍 Rechercher un spot, trail..."
            className="flex-1 px-3 py-2 bg-[var(--bg)]/90 backdrop-blur-sm border border-white/10 rounded-xl text-white placeholder-gray-500 text-sm focus:border-[var(--accent)] focus:outline-none focus-visible:ring-2 focus-visible:ring-[var(--accent)]"
            style={{fontSize:'14px'}}
            aria-label="Rechercher sur la carte"
          />
          <button
            type="button"
            onClick={handleSearch}
            className="px-3 py-2 bg-[var(--accent)] text-white rounded-xl text-sm font-medium hover:opacity-90 transition focus:outline-none focus-visible:ring-2 focus-visible:ring-white"
            style={{fontSize:'14px'}}
            aria-label="Rechercher"
          >
            OK
          </button>
        </div>
        <div className="flex gap-1.5 overflow-x-auto no-scrollbar">
          <button
            type="button"
            className={`px-2.5 py-1 rounded-full text-xs whitespace-nowrap transition focus:outline-none focus-visible:ring-2 focus-visible:ring-[var(--accent)] ${!sportFilter ? 'bg-[var(--accent)] text-white' : 'bg-[var(--bg)]/80 text-gray-300 hover:bg-[var(--bg)]'}`}
            onClick={() => setSportFilter(null)}
            style={{fontSize:'14px'}}
            aria-label="Tous les sports"
          >
            Tous
          </button>
          {sports.slice(0, 8).map(s => (
            <button
              key={s}
              type="button"
              className={`px-2.5 py-1 rounded-full text-xs whitespace-nowrap transition focus:outline-none focus-visible:ring-2 focus-visible:ring-[var(--accent)] ${sportFilter === s ? 'bg-[var(--accent)] text-white' : 'bg-[var(--bg)]/80 text-gray-300 hover:bg-[var(--bg)]'}`}
              onClick={() => setSportFilter(sportFilter === s ? null : s)}
              style={{fontSize:'14px'}}
              aria-label={`Filtrer par ${s}`}
            >
              {getSportEmoji(s)} {s}
            </button>
          ))}
        </div>
      </div>

      {/* Map */}
      <div
        ref={mapContainerRef}
        className="flex-1 w-full"
        aria-label="Carte interactive des spots outdoor"
      />

      {/* My location button */}
      <button
        type="button"
        className="absolute bottom-32 right-3 z-[1000] w-10 h-10 bg-[var(--bg)]/90 backdrop-blur-sm rounded-full flex items-center justify-center border border-white/10 hover:bg-white/10 transition focus:outline-none focus-visible:ring-2 focus-visible:ring-[var(--accent)]"
        onClick={() => {
          if (mapRef.current) {
            mapRef.current.map.setView([45.87, 6.86], 12);
            showToast('Position centrée sur Chamonix', 'info', '📍');
          }
        }}
        aria-label="Ma position actuelle"
      >
        📍
      </button>

      {/* Spot detail panel */}
      {selectedSpot && (
        <div className="absolute bottom-20 left-2 right-2 z-[1000] bg-[var(--card)] rounded-2xl p-4 border border-white/10 shadow-2xl animate-slideUp">
          <div className="flex items-start gap-3">
            <div className="w-12 h-12 rounded-xl bg-white/5 flex items-center justify-center text-2xl">{selectedSpot.emoji}</div>
            <div className="flex-1">
              <h3 className="font-bold text-sm">{selectedSpot.name}</h3>
              <p className="text-sm text-gray-400" style={{fontSize:'14px'}}>
                {selectedSpot.type} · ⭐ {selectedSpot.rating} · {getSportEmoji(selectedSpot.sport)} {selectedSpot.sport}
              </p>
              {selectedSpot.description && (
                <p className="text-sm text-gray-300 mt-1" style={{fontSize:'14px'}}>{selectedSpot.description}</p>
              )}
            </div>
            <button
              type="button"
              onClick={() => setSelectedSpot(null)}
              className="text-gray-500 hover:text-white focus:outline-none focus-visible:ring-2 focus-visible:ring-[var(--accent)] rounded p-1"
              aria-label="Fermer le détail"
            >
              ✕
            </button>
          </div>

          {/* Qui y va */}
          <div className="mt-3 flex items-center gap-2">
            <span className="text-xs text-gray-400" style={{fontSize:'14px'}}>Qui y va :</span>
            {NEARBY_PEOPLE.slice(0, 3).map(p => (
              <button
                key={p.id}
                type="button"
                onClick={() => setSubPage({ type: 'user-profile', userId: p.id })}
                className="w-7 h-7 rounded-full bg-white/10 flex items-center justify-center text-sm hover:ring-2 hover:ring-[var(--accent)] transition focus:outline-none focus-visible:ring-2 focus-visible:ring-[var(--accent)]"
                aria-label={`Profil de ${p.name}`}
              >
                {p.avatar}
              </button>
            ))}
          </div>

          <button
            type="button"
            className="w-full mt-3 py-2.5 bg-[var(--accent)] text-white rounded-xl font-medium text-sm hover:opacity-90 transition focus:outline-none focus-visible:ring-2 focus-visible:ring-white"
            onClick={() => setSubPage({ type: 'trail-detail', trailId: selectedSpot.id })}
            aria-label="Voir le détail du spot"
          >
            Voir le détail →
          </button>
        </div>
      )}
    </div>
  );
}

