  description: 'Itinéraire classique de l\'ascension du Mont-Blanc via le parcours des Trois Monts. Dénivelé important, passages rocheux et alpins, glacier. À faire en très bonne condition physique.',
  location: 'Chamonix, France',
  gradient: 'linear-gradient(135deg, rgb(34, 197, 94), rgb(59, 130, 246))',
  conditions: [
    { author: 'Alex Climber', date: 'Aujourd\'hui', status: 'Ouvert', comment: 'Neige jusqu\'à 2500m, très bon équipement indispensable' },
    { author: 'Marie Ridge', date: 'Hier', status: 'Ouvert', comment: 'Conditions météo moyennes, vent fort en altitude' },
    { author: 'Luc Mountain', date: 'Il y a 2j', status: 'Ouvert', comment: 'Glacier bien visible, chaîne recommandée' },
  ],
  weather: { temp: -8, condition: 'Partiellement nuageux', humidity: 45 },
  participants: [
    { id: 'user-1', name: 'Sophie', avatar: '👩‍🎓' },
    { id: 'user-2', name: 'Thomas', avatar: '👨‍💼' },
    { id: 'user-3', name: 'Claire', avatar: '👩‍🔬' },
    { id: 'user-4', name: 'Marc', avatar: '👨‍⚕️' },
  ],
  elevation_data: [1000, 1200, 1500, 1800, 2100, 2400, 2700, 3000, 3300, 3500, 4000, 4200, 4300, 4400, 4500, 4600, 4700, 4800],
};

function ElevationProfile({ data }: { data: number[] }) {
  const max = Math.max(...data);
  const min = Math.min(...data);
  const range = max - min;

  return (
    <svg viewBox="0 0 100 30" className="w-full h-24" aria-label="Profil d'élévation du sentier">
      <defs>
        <linearGradient id="elevGradient" x1="0%" y1="0%" x2="0%" y2="100%">
          <stop offset="0%" stopColor="rgb(59, 130, 246)" stopOpacity="0.8" />
          <stop offset="100%" stopColor="rgb(59, 130, 246)" stopOpacity="0.2" />
        </linearGradient>
      </defs>
      <polyline
        points={data
          .map((v, i) => {
            const x = (i / (data.length - 1)) * 100;
            const y = 30 - ((v - min) / range) * 25;
            return `${x},${y}`;
          })
          .join(' ')}
        fill="none"
        stroke="rgb(59, 130, 246)"
        strokeWidth="0.8"
      />
      <polygon
        points={`0,30 ${data
          .map((v, i) => {
            const x = (i / (data.length - 1)) * 100;
            const y = 30 - ((v - min) / range) * 25;
            return `${x},${y}`;
          })
          .join(' ')} 100,30`}
        fill="url(#elevGradient)"
      />
    </svg>
  );
}

